for rel, (old, new) in index_replacements.items():
    path = ROOT / rel
    text = path.read_text(encoding="utf-8")
    if old in text:
        path.write_text(text.replace(old, new), encoding="utf-8", newline="\n")


for section, (alt, caption) in figure_replacements.items():
    chapter = "module-27-visual-perception-for-action" if section.startswith("27.") else "module-28-3d-perception-and-neural-scene-representations"
    path = ROOT / "part-6-embodied-perception" / chapter / f"section-{section}.html"
    text = path.read_text(encoding="utf-8")
    start = text.find('<figure class="illustration">')
    if start == -1:
        continue
    end = text.find("</figure>", start) + len("</figure>")
    block = text[start:end]
    src_start = block.find('src="')
    src_end = block.find('"', src_start + 5)
    src = block[src_start + 5:src_end]
    new_block = (
        '<figure class="illustration">\n'
        f'<img alt="{alt}" loading="lazy" src="{src}"/>\n'
        f'<figcaption><strong>Figure {section}A</strong>: {caption}</figcaption>\n'
        '</figure>'
    )
    path.write_text(text[:start] + new_block + text[end:], encoding="utf-8", newline="\n")
